alert tcp  \$EXTERNAL_NET  \$HTTP_PORTS -> \$HOME_NET any
msg: "BROWSER-IE Microsoft Internet Explorer CacheSize exploit attempt";
flow: to_client, established;
file_data;
    content:"recordset"; offset:14; depth:9;
